```

**Nostr channel.ts** (`/extensions/nostr/src/channel.ts`) has similar structure but with:
- DM-only capabilities: `chatTypes: ["direct"]`
- No media support: `media: false`
- Active bus-based gateway with lifecycle management
- Profile publishing capabilities
- Custom HTTP handler registration in index.ts

Key differences:
```typescript
export const nostrPlugin: ChannelPlugin<ResolvedNostrAccount> = createChatChannelPlugin({
  // Similar base structure
  gateway: {
    startAccount: async (ctx) => {
      const bus = await startNostrBus({
        accountId: account.accountId,
        privateKey: account.privateKey,
        relays: account.relays,
        authorizeSender: async ({ senderPubkey, reply }) => { ... },
        onMessage: async (senderPubkey, text, reply, meta) => { ... },
        onError: (error, context) => { ... },
        // ... lifecycle callbacks
      });
      activeBuses.set(account.accountId, bus);
      return { stop: () => { bus.close(); } };
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const bus = activeBuses.get(aid);
      await bus.sendDm(normalizedTo, message);
      return attachChannelToResult("nostr", { to: normalizedTo, messageId: ... });
    },
  },
});

